sql:
SELECT SUM(gp.total_rent_paid + gp.total_rent_collected) AS total_rent
FROM game_player gp
WHERE gp.game_id = 1;

SELECT AVG(gp.current_cash) AS average_total_cash
FROM game_player gp
WHERE gp.game_id = 1 AND gp.is_bankrupt = 0;

SELECT name, cost
FROM property
ORDER BY cost ASC;

SELECT current_cash, properties_owned
FROM game_player
WHERE game_id = 1;

SELECT SUM(total_rent_paid) AS total_rent_paid
FROM game_player
WHERE game_id = 1;

external_knowledge:
- The ranking is based on the total rent collected by each player within a game session;
- A game session is identified by a unique game ID and has a name;
- The players are ranked in descending order of the total rent collected;
- "Top three" refers to the players with the highest total rent collected in each game session.

sql:
SELECT rent
FROM property
WHERE property_id = 1;

SELECT player_name
FROM player
WHERE player_id = 1;

SELECT name, group_id, cost
FROM property
ORDER BY cost DESC;

external_knowledge:
- 'Monopoly' is a board game where players buy and trade properties and collect rent from their opponents.;
- 'Paid more than 1000 coins in rent' refers to the total amount of rent paid by a player across all their finished games being greater than 1000.;
- 'Games that have come to a conclusion' refers to games with a status of 'finished'.;

sql:
SELECT name, cost
FROM property
WHERE cost = (SELECT MAX(cost) FROM property);

SELECT SUM(gp.total_rent_collected) AS total_rent_collected_in_game
FROM game_player gp
WHERE gp.is_bankrupt = 0;

external_knowledge:
- "Monopoly" is a board game where players buy, sell, and develop properties;
- "Current game session" refers to a specific instance of the game with ID 1;
- "Paid rent" is the total amount a player has paid to other players for landing on their properties;
- "Collected rent" is the total amount a player has received from other players for landing on their properties.

sql:
SELECT COUNT(*) AS number_of_properties_owned
FROM game_player
WHERE player_id = (SELECT player_id FROM player WHERE player_name = 'Alice Johnson');

external_knowledge:
- "Crown jewels" refers to the most valuable properties;
- The total cost of a property includes the base cost and all improvements;
- The property IDs are stored as a comma-separated list in the `properties_owned` column.
